import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { API_MOVIE, API_KEY, POSTER_PATH, WIDTH_300, API_TV } from '../constant';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import { FiChevronLeft, FiChevronRight } from 'react-icons/fi';

const CastList = (props) => {

  const [data, setData] = useState([]);
  const { id, name } = props;

  let api;
  switch (name) {
    case 'movie':
      api = API_MOVIE;
      break;

    case 'tv':
      api = API_TV;
      break;

    default:
      break;
  }

  useEffect(() => {
    const getData = async () => {
      await fetch(api + id + '/credits?api_key=' + API_KEY)
        .then((response) => {
          return response.json();
        })
        .then((data) => {
          setData(data.cast);
        })
        .catch((error) => {
          console.error(error);
        })
    }

    getData();
  }, [api, id]);
  
  const ref = useRef(null);

  const scrollRight = (scrollOffset) => {
    ref.current.scrollLeft -= scrollOffset;
  };

  const scrollLeft = (scrollOffset) => {
    ref.current.scrollLeft += scrollOffset;
  };

  return (
    <>
      {data.length > 0 ?
        <div className="position-relative">
          <h2 className="mt-5">Cast</h2>
          <button className="btn btn-secondary position-absolute scroll-button1" onClick={() => scrollRight(500)}><FiChevronLeft /></button>
          <button className="btn btn-secondary position-absolute scroll-button2" onClick={() => scrollLeft(500)}><FiChevronRight /></button>
          <div className="cast-row" ref={ref}>
            {data.map((dataRow, index) => (
              <Link key={index} className="card-link" to={'/movieshub/person/' + dataRow.id}>
                <div className="card frameWidth" key={index}>
                  <LazyLoadImage className="card-img-top" src={POSTER_PATH + WIDTH_300 + dataRow.profile_path} effect="opacity" alt={dataRow.name} onError={(e) => { e.target.onerror = null; e.target.src = "https://fakeimg.pl/300x450?text=MoviesHub&font=bebas&font_size=35" }} />
                  <div className="card-body">
                    <div className="card-text">
                      <div>{dataRow.name}</div>
                      <div className="text-muted">{dataRow.character}</div>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div> : ''}
    </>
  )
}

export default CastList
